import dom from './templates/MetaDataInfo.ejs';
export class ControlEditor {

    constructor(control) {
        this.control = control;
        this.isMouseDown = false;
    }
    init() {
        let _this = this;
        var div = $("<div class='ds_control_design '/>");
        var tools = $("<div/>");
        var qs = ["QsRadio", "QsCheckBox", "QA", "Fill", "QsRate", "QsSlider", "QsHelloMsg"];
        if (this.control.$metadata) {
            if (this.control.root._pageDesign && this.control.root._pageDesign.options.controlMetadataInfo.show) {
                // console.log(this.control.$metadata);
                let cmap=getControlMap(this.control.ctrl_type);
                let code = this.control.$metadata.id.split(".");
                let suffix = code.slice(0, code.length - 1).join("_");
                this.control.$metadata.groupName = this.control.$metadata.groupName || "无";
                let str = "控件类型:" + cmap.text + "\r\n" +
                    "元数据标识:" + (this.control.$metadata.id || "无") + "\r\n" +
                    "元数据名称:" + (this.control.$metadata.name || "无") + "\r\n" +
                    "元数据组：" + (this.control.$metadata.groupName || '无');
                let data = {
                    "ctrlType":cmap.text,
                    "metadataCode": suffix ? suffix + "." + code[code.length - 1] : "无",
                    "metaName": this.control.$metadata.name,
                    "groupName": this.control.$metadata.groupName
                }
                var metacode = $("<span class='ds_metadatadeg design-tools-button layui-badge layui-bg-green' title='" + str + "'>详情</span>");
                metacode.on("click", evt => {
                    openMetaInfo(data)
                });
                metacode.appendTo(tools);
            }

        }
        var dropButton = $("<span class='ds_dragbadeg design-tools-button layui-badge layui-bg-orange'>拖动</span>");
        var removeButton = $("<span class='ds_removebadeg design-tools-button layui-badge layui-bg-blue'>移除</span>");
        dropButton.appendTo(tools);
        removeButton.appendTo(tools);
        // if (qs.indexOf(this.control['ctrl_type']) > -1) {
        if(this.control.baseSetting){
            var setButton = $("<span class='ds_setbadeg design-tools-button layui-badge layui-bg-yellow'>设置</span>");
            setButton.on("click", evt => {
                var _this = this;
                dsf.layer.openDialog({
                    title: this.control.baseSetting.title,
                    content: dsf.url.getAbsolutePath(this.control.baseSetting.settingHtmlPath),
                    args: {
                        owner: this.control
                    },
                    area: [this.control.baseSetting.width, this.control.baseSetting.height],
                    btn: [{
                        text: "完成编辑",
                        handler: function(index, layero, win) {
                            let result = win.getDialogResult();
                            _this.control.visible=result.visible;
                            _this.control.isNumber=result.isNumber;
                            $.extend(_this.control, result);
                            _this.control.render();
                        }
                    }, {
                        text: "取消",
                        handler: function() {
                            return true;
                        }
                    }]
                });
            });
            setButton.appendTo(tools);
        }
        // console.log("d")
        if ((this.control instanceof dsf.Controls.DataGrid) || (this.control instanceof dsf.Controls.LayoutControl)) {
            div.addClass("ds_container_design");
        }
        tools.appendTo(div);
        this.control.element.append(div);
    }
    mouseDown(evt) {
        this.isMouseDown = true;
    }
    moouseUp(evt) {
        this.isMouseDown = false;
    }
    mouseMove(evt) {

    }
    contextMenu(evt) {
        // return false;
    }
    cancelEdit() {
        this.control.element.removeClass("ds_control_selected");
    }

    // renderDesginer(){}
}

function openMetaInfo(meta) {
    let div = dom(meta);
    layer.open({
        type: 1,
        content: div, //这里content是一个普通的String
        area: ["400px", "300px"]
    });
}

function getControlMap(type){
    return {
        text:window._controlMap.className[type].name,
        value:window._controlMap.className[type].code,
    }
}
