function map(name, code, className) {
    return function(target) {
        target.ctrl_code = code;
        target.prototype.ctrl_type = className;
        target.prototype.ctrl_code = code;
        if (!window._controlMap) {
            window._controlMap = {
                code: {},
                className: {}
            };
        }
        window._controlMap.code[code] = {
            name: name,
            target: className,
            code: code,
            handler: target
        }
        window._controlMap.className[className] = {
            name: name,
            target: className,
            code: code,
            handler: target
        }
    }
}

export {
    map
}